import React from 'react';
import './Home.css';
import rumanSquare from '../assets/rumanSquare.png';

function Home() {
  return (
    <section id="home" style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', backgroundColor: '#f4f4f4' }}>
      <img src={rumanSquare} alt="Ruman" style={{ maxWidth: '100%', height: 'auto' }} />
    </section>
  );
}

export default Home;
